#!/usr/bin/env bash
# Fake gh CLI for evals: logs every call, serves canned issue data.
echo "gh $*" >> .gh-calls.log
case "$1 $2" in
  "auth status") echo "Logged in to github.com (fake)"; exit 0 ;;
  "repo view") echo '{"nameWithOwner":"acme/csvkit-demo"}'; exit 0 ;;
  "label list") printf 'bug\tSomething is broken\t#d73a4a\nenhancement\tNew feature\t#a2eeef\ntriaged\tSeen by triage\t#ededed\n'; exit 0 ;;
  "issue list") cat .fixture/issue-list.json; exit 0 ;;
  "issue view") cat ".fixture/issue-$3.txt"; exit 0 ;;
  "search issues") cat .fixture/search.txt; exit 0 ;;
  "pr list") echo "[]"; exit 0 ;;
  "issue edit"|"issue comment"|"issue close"|"label create") exit 0 ;;
  *) echo "{}"; exit 0 ;;
esac

